import Foundation

struct Quiz {
    let question: String
    let choices: [String]
    let answer: Int
    let explanation: String
}

let KumamotoQuizzes: [Quiz] = [
    Quiz(question: "加藤清正は秀吉の命令で朝鮮出兵した文禄、慶長(けいちょう)の役(えき)の時に兵糧(ひょうろう)の確保に苦しみ．あまりの空腹に耐えかね馬すらも口にしたという苦い経験があり、それゆえ熊本城を建てた時には兵糧の確保を頑張ったと言われるが、ここで問題です。熊本城で籠城した時のことを考えて食べられるものとして植えたとされる木は何ですか", choices: ["かきの木","どんぐりの木","みかんの木","銀杏の木"], answer: 3, explanation: "熊本城は別名を銀杏城という。いざという時に食べられる銀杏のなるイチョウの木が多く植えられていた。"),
    Quiz(question: "清正は熊本城を建てる時、籠城して戦うことを考えてうまいこと兵糧を確保をしました。壁に何をかくしていたのでしょうか。", choices: ["米つぶ","馬の干し肉","じゃかいも","干瓢"], answer: 3, explanation: "非常時には壁を崩して食べられるようにするために干瓢が練り込まれていた。熊本城は「食べられる城」とも呼ばれていた。"),
    Quiz(question: "清正は石垣作りの名人と言われており、防御力を高めるためによじ登ることが困難な角度の急なの石垣を作りましたが、何というものでしょうか。", choices: ["つばめ返し","忍者返し","武者返し","借金返し"], answer: 2, explanation: "石垣は扇のように反り返っていることが特徴。石垣の下の方はゆるやかだが、上に向かうとほぼ垂直になる。登れそうに見えて忍者でも登れないことから「武者返し」と呼ばれている。"),
    Quiz(question: "清正公は籠城する時のために作ったものは何でしょうか", choices: ["抜け道としてのトンネル","長い戦いに備えての大きなお風呂","120箇所の井戸","大きなくみ取り式のトイレ"], answer: 2, explanation: "清正は朝鮮出兵時に籠城を経験して水の大切さを痛感(つうかん)した。そのため城内に120の井戸があり飲み水も確保もした。井戸は30尺(39m)にも達しています。"),
    Quiz(question: "石垣作りの名人とされた清正公ですが2016年の熊本地震で8段12個の石垣だけでギリギリの状態で櫓を支えた奇跡の一本石垣はどの櫓か。", choices: ["宇土櫓","飯田丸五回櫓","監物櫓","北十八間櫓"], answer: 1, explanation: "飯田丸五回櫓は熊本城本丸の南を守っていた場所です。熊本地震で約580石が崩落して角の石垣『隅石』(すみいし)のみで建物を支えていたため「奇跡の一本石垣」と呼ばれました。"),
    Quiz(question: "加藤清正が朝鮮を攻めた時に退治した、どうもうな動物とは何でしょうか。", choices: ["熊","ライオン","黒豹","虎"], answer: 3, explanation: "当時の朝鮮半島には野生の虎がたくさんいて清正の陣地の近くにも巨大な虎が現れた。伝説では、清正自ら虎退治に乗り出し、槍一本でその巨大な虎を仕留めたとなっている。"),
    Quiz(question: "熊本城を作った加藤清正が朝鮮出兵の時に現地に送った兵糧に含まれるものはどれか?", choices: ["イワシ","スズキ","タラ","ヒラメ"], answer: 0, explanation: "清正は塩イワシを送った。イワシはオメガ3脂肪酸を多く含んでいる。「腐ってもタイ」と言われているタイの２倍以上オメガ３脂肪酸が含まれている。オメガ3脂肪酸は体内で作ることができないため食物から取る必要があります。オメガ3脂肪酸は脳が正しく動き発達するために必要です。炎症や血栓も抑えます。")
]

let MatsumotoQuizzes: [Quiz] = [
    Quiz(question: "日本の城で五つしかない国宝のうちの一つ、松本城はどこにあるでしょうか。", choices: ["兵庫県","長野県","岡山県","新潟県"], answer: 1, explanation: "松本城は長野県の松本にある。松本は北アルプスを望み、美しい水が溢れる肥沃の地である。古来より多くの人々が定住し交通の要で軍事的に重要な拠点に築かれた。"),
    Quiz(question: "日本100名城の城の内、90以上の城に別名がある。その中から松本城の別名は、", choices: ["白帝城","馬場城","兜城","烏城"], answer: 3, explanation: "松本城が烏城と呼ばれているかというと天守が黒漆塗りで黒くて烏に似ているからです。"),
    Quiz(question: "人は今、世界で増え続けている。昔に松本城を築いた人は?", choices: ["武田信玄","徳川家康","石川数正","豊臣秀吉"], answer: 2, explanation: "石川数正は徳川家康の家臣から豊臣秀吉の家臣になった。数正は武将としても一流だった。秀吉の九州責めに功をあげ信州松本において八万石を与えられた。松本城は数正がその基礎を作った。"),
    Quiz(question: "今は丁度いい角度の階段。松本城はお城の中で日本一急な階段がある。その階段の角度は？", choices: ["23度","59度","72度","61度"], answer: 3, explanation: "階段は急勾配で踏み板の踏み幅は狭くかつ蹴上(踏み板の段差)が高い。四階の階段の勾配は61度もあり最大の蹴り上げは39cmの高さである。敵兵の侵入を防ぐ工夫である。"),
    Quiz(question: "今、積むのはつみき。昔、お城に積んでいた石垣。松本城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 2, explanation: "切り出してほとんど加工しないで積み上げるのが野面積。最も古い時代の積み方。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、松本城であった事件とは？", choices: ["お城が傾いた","松本城の宝が無くなった","石川数正を裏切った人がいた","松本城が崩れた"], answer: 0, explanation: "江戸前期の松本藩で大きな農民一揆が起こり、鎮圧された。藩は約束をはごにしたうえとらえたものを処刑した。指導者の加助ははりつけにされた時、「わしの一念で城の天守閣を傾けて見せる」と天守を睨んでから処刑された。すると松本城天守は西へ少し傾いた。何度も傾きを直そうとしてもすぐまた傾いてしまう。加助の祟りだと言われている。"),
    Quiz(question: "松本城の大規模な改修を行った武田信玄は、城を守る上で必要な物質として「米、大豆、薪、味噌、塩、糠、青魚のあら、乾魚、海藻」をあげている。この中でオメガ３脂肪酸が含まれるものはどれか。", choices: ["米","大豆","糠","青魚のあら"], answer: 3, explanation: "サバ、さんま、イワシなどの青魚にはオメガ３脂肪酸が含まれる。青魚のあら、煮干しなど。あらには刺身部分には少ないオメガ３脂肪酸が集中している。オメガ３脂肪酸は健康に良く、頭も良くなる。")
]

let MatsueQuizzes: [Quiz] = [
    Quiz(question: "日本の城で五つしかない国宝のうちの一つで、現存12天守に含まれる松江城はどこにあるでしょうか。", choices: ["青森県","島根県","福島県","鳥取県"], answer: 1, explanation: "島根県の宍道湖畔の亀田山(標高29m)に築城された。松江市は海と湖と山に囲まれた地域で「水の都」として知られる歴史と自然が調和した城下町です。"),
    Quiz(question: "日本100名城の城の内、90以上の城に別名がある。その中から松江城の別名は、", choices: ["鷹城","鶴島城","千鳥城","金鳥城"], answer: 2, explanation: "チドリが羽を広げたように見える破風から、別名を千鳥城という。一階と二階が同じ大きさのためどしっりした印象の城です。"),
    Quiz(question: "人は今、世界で増え続けている。昔に松江城を築いた人は?", choices: ["堀尾吉晴","生駒親正","小笠原忠真","本多利朝"], answer: 0, explanation: "堀尾吉晴は豊臣秀吉に仕え、武勇に加え温和で誠実な面を持ち合わせて「仏の茂助」と呼ばれて人望を集めた武将である。"),
    Quiz(question: "今は丁度いい角度の階段。松江城の天守内部の階段の角度は？", choices: ["47度","50度","43度","32度"], answer: 1, explanation: "松江城の天守内部の階段は、50度以上の傾斜がある非常に急な「はしご状」で、かつ敵の侵入を防ぐために取り外しやすい「桐」の木で作られています。"),
    Quiz(question: "今、積むのはつみき。昔、お城に積んでいたのは石垣。松江城の石垣の積み方は？", choices: ["まづめ石の野面積","切込接と野面積","野面積と打込接","らん積の野面積"], answer: 2, explanation: "自然石をそのまま積む「野面積み」と加工した石を積む「打ち込み接ぎ」が混在し、築城（1611年完成）の際に穴太衆（あのうしゅう）により築かれました。約31種類、1,100個以上の刻印が見つかっており、大手門跡付近にはハート形の石があることで知られる、歴史的価値の高い構造物です。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、松江城であった事件とは？", choices: ["城が滅びた","黒松が根こそぎ倒れた","石垣の石が落ちた","将軍がいなくなった"], answer: 1, explanation: "2025年3月13日、松江城の堀に高さ21メートルの巨大なクロマツが倒れ込んでいるのが発見された。原因はキノコによる幹の空洞化で、城山公園の巨大クロマツが根元から折れていた。"),
    Quiz(question: "松江城の近くで取れるオメガ３が多く入った魚は何か", choices: ["スズキ","ウナギ","シラウオ","コイ"], answer: 1, explanation: "松江城のすぐ近くに広がる宍道湖（しんじこ）では、夏にウナギがよく取れます。ウナギにはオメガ3脂肪酸が多く含まれており、血流を良くしてくれるので老化を防ぐ効果や頭を良くしてくれる効果があります。大昔から元気になる薬の役目をはたし万葉集の大伴家持の歌にもあります。")
]

let MarukameQuizzes: [Quiz] = [
    Quiz(question: "日本百名城のうちの一つ、丸亀城はどこにあるでしょうか。", choices: ["山形県","福島県","鳥取県","香川県"], answer: 3, explanation: "香川県丸亀市は、日本一高い石垣を誇る「丸亀城」を中心に栄えた、歴史と自然が調和する瀬戸内海沿岸の街です。温暖少雨で災害が少なく、子育て・介護環境が充実しており、住みよい街ランキング（中国・四国地方1位）でも高評価を得ています。特産はうちわや骨付き鳥です。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から丸亀城の別名は、", choices: ["横山城","鯉城","亀山城","久松城"], answer: 2, explanation: "前者は築城された「亀山」という丘陵に由来し、後者は美しい石垣の景観が、仙人が住むと言われる蓬莱山に見立てられたことに由来します。"),
    Quiz(question: "人は今、世界で増え続けている。昔に丸亀城を築いた人は?", choices: ["池田光政","生駒親正","黒田長政","中川秀成"], answer: 1, explanation: "織田信長と豊臣秀吉に仕え、秀吉政権下で「三中老」に名を連ねた17万石の大名です。卓越した策略家として知られ、戦国から江戸初期の激動期を生き抜き、讃岐国（香川県）高松の礎を築きました。関ヶ原の戦いでは親正が西軍、子が一正が東軍に属し、家を残したことでも有名です。"),
    Quiz(question: "今は丁度いい角度の階段。丸亀城の天守内部の階段の角度は？", choices: ["29度","38度","57度","43度"], answer: 2, explanation: "ほぼ垂直に近い角度で、実質的に「梯子（はしご）」に近い形状です。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。丸亀城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 3, explanation: "丸亀城の石垣は、主に江戸時代初期の技術を用いた「打ち込みハギ」や「切り込みハギ」で、美しく反り返った「扇の勾配」の高石垣です。大手門付近には切石積みや粗加工石積み、南東山麓には野面積みも見られます。本丸まで4段に重なる石垣の高さは、合計で60m。4段を合わせた高さでは日本一だ‼︎"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、丸亀城であった事件とは？", choices: ["天守閣が壊れた","築城者が行方不明になった","石垣の石が落ちた&イノシシ出没","将軍が裏切った"], answer: 2, explanation: "西日本豪雨により崩落。現在も2028年3月の完了を目指して復旧作業中。丸亀城内で散歩中の女性がイノシシと衝突する事故が発生。"),
    Quiz(question: "丸亀城の近くでオメガ３の入った魚が取れる。その魚は何か", choices: ["イワシ","カレイ","タラ","キス"], answer: 0, explanation: "ニシン科やカタクチイワシ科の魚の総称で、日本沿岸の広範囲に群泳する青魚です。DHAやEPA、カルシウムが非常に豊富で、特に梅雨時期の「入梅いわし」は脂がのって非常に美味です。刺身、煮干し、丸干しなど幅広い料理で親しまれています。")
]

let InuyamaQuizzes: [Quiz] = [
    Quiz(question: "日本の城で五つしかない国宝のうちの一つで、現存12天守に含まれる犬山城はどこにあるでしょうか。", choices: ["大阪府","栃木県","新潟県","愛知県"], answer: 3, explanation: "犬山城は愛知県犬山市にあり、木曽川(きそがわ)の南岸、標高約80mの断崖に建つ現存最古の天守を持つ国宝の城です。戦国時代には交通の要衝として激戦の舞台となりました。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から犬山城の別名は、", choices: ["丸山城","山城","無鶴城","白帝城"], answer: 3, explanation: "江戸時代の儒学者・荻生徂徠(おぎゅうそらい)が、木曽川沿いの小高い山に立つ城の風景を中国・長江流域の景色を詠った李白の詩「早発白帝城」になぞらえて命名したと伝えられています。"),
    Quiz(question: "人は今、世界で増え続けている。昔に犬山城を築いた人は?", choices: ["徳川家康","織田信康","山内一豊","藤堂高虎"], answer: 1, explanation: "織田信康は戦国時代の武将で織田信長の叔父です。(織田信長のお父さんの弟)1545年(天文13年)齋藤道三との戦いで討死した。"),
    Quiz(question: "今は丁度いい角度の階段。犬山城の最上階(三階)に続く階段の角度は？", choices: ["29度","38度","42度","50度"], answer: 3, explanation: "最上階付近は約50度という非常に急な角度。敵の侵入を防ぐもの。階段は上るというより梯子を登る感覚に近い。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。犬山城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 2, explanation: "犬山城石垣は主に自然石を加工せず積み上げる「野面積」が特徴で石同士の隙間が大きく荒々しい。天守の石垣は最も高い場所で約6mの高さがあり、現存石垣としては非常に高い部類に入ります。木曽川の岩「チャート」という固い岩石が使用されています。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、犬山城であった事件とは？", choices: ["城主が自殺した。","スギの木が根こそぎ倒れた","石垣が崩れた","雷でしゃちほこが壊れた"], answer: 3, explanation: "2017年の落雷によって瓦製(かわらせい)のしゃちほこがほぼ全壊。屋根瓦(かわら)も損傷(そんしょう)した。"),
    Quiz(question: "織田信長は本能寺で明智光秀に襲われ亡くなったが、その事件が無くとも早死にしたと考えられる。信長は早食いで好き嫌いが多かったとされるからである。塩辛い田舎料理を好んだ。血圧が高くなり、心臓を悪くしてなくなる可能性が高かった。一方で、織田信長のいた戦国時代に好まれていた食べ物は何か？", choices: ["ヒラメの刺身","タラの唐揚げ(からあげ)","ブリの干物","カレイの煮付け"], answer: 2, explanation: "保存性の高いブリの干物。ブリはオメガ３脂肪酸を多く含んでいる。青魚の中でもトップクラスに多い。100gあたり約2640mgものDHA・EPA（オメガ３脂肪酸）をふくんでいる。いたみにくいように干物にして保存されていた。")
]

let KinojoQuizzes: [Quiz] = [
    Quiz(question: "日本百名城のうちの一つ、鬼ノ城はどこにあるでしょうか。", choices: ["三重県","群馬県","岡山県","富山県"], answer: 0, explanation: "三重県熊野市は、世界遺産の「熊野古道」や「鬼ヶ城」に代表される、山・川・海の壮大な自然と歴史に囲まれた「蘇りの地」です。温暖な気候で、柑橘類「新姫」や熊野地鶏、めはり寿司などのグルメも楽しめます。シーカヤックやハイキングなどのアウトドアが人気です。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から鬼ノ城の別名は、", choices: ["松尾城","千代田城","矢留城","鬼城山"], answer: 3, explanation: "その名は、この地に居座り略奪を繰り返したという百済の王子・温羅（うら）という「鬼」が籠もった城である、という「温羅伝説」に由来しています。"),
    Quiz(question: "人は今、世界で増え続けている。昔に鬼ノ城を築いた人は?", choices: ["豊臣秀吉","まだ、築いた人がわかっていない","鍋島直正","藤堂高虎"], answer: 1, explanation: "『日本書紀』に記載がなく「謎の城」ですが、当時の吉備地方の有力者や大宰・総領（石川王の説あり）が指揮して築いた可能性が高いとされています。"),
    Quiz(question: "今は丁度いい角度の階段。鬼ノ城の天守内部の階段の角度は？", choices: ["64度","階段なし","53度","24度"], answer: 1, explanation: "近世城郭のような「天守」や内部の階段は存在しません。復元されているのは西門、城壁、角楼などです。7世紀の古代山城であり、建物は地面に柱を埋め込む掘立柱建物（ほったてばしらたてもの）が中心で、石垣や土塁が主な見どころです。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。鬼ノ城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 2, explanation: "要所や断崖には強固な石垣が築かれています。特に「屏風折れ」と呼ばれる城壁の屈曲部や、西門、東門周辺に見られる、崩壊を防ぐために石畳（敷石）が武者走り状に配置された構造が特徴的です。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、鬼ノ城であった事件とは？", choices: ["殺人事件","津波","火事","転落事故"], answer: 3, explanation: "鬼ヶ城（三重県熊野市）で1960年代に起きた転落死亡事故を巡る、国（行政）の損害賠償責任が争点となった裁判（最高裁昭和50年11月28日判決）です。自然の景勝地において、管理者がどこまで安全対策を講じる義務があるかが問われた、国家賠償法上の重要判例です。 "),
    Quiz(question: "鬼ノ城の近くでオメガ３の入った魚が取れる。その魚は何か", choices: ["イワシ","サケ","アユ","メバル"], answer: 0, explanation: "イワシ（鰯）は、ニシン目ニシン科やカタクチイワシ科に属する小魚の総称で、マイワシ、ウルメイワシ、カタクチイワシの3種が代表的。沿岸の表層を大群で泳ぎ、プランクトンを食べる。非常に鮮度が落ちやすく「弱い魚」という漢字の由来になったとされる。栄養価が極めて高く、EPAやDHA、カルシウムを豊富に含む青魚の代表格である。")
]

let AzutiQuizzes: [Quiz] = [
    Quiz(question: "日本百名城のうちの一つ、安土城はどこにあるでしょうか。", choices: ["佐賀県","滋賀県","埼玉県","山梨県"], answer: 3, explanation: "滋賀県近江八幡市の安土（あづち）は、織田信長が築いた「安土城」を中心に栄えた、歴史的価値の高い町です。琵琶湖東岸に位置し、国の特別史跡「安土城跡」をはじめ、考古博物館や復元された天主など、戦国文化を今に伝える名所が多数あります。穏やかな自然と歴史が融合したエリアです。 "),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から安土城の別名は、", choices: ["金亀城","稲葉山城","福山城","なし"], answer: 3, explanation: "安土城は、織田信長が近江国（現・滋賀県）の「安土山」に築いた城で、別名は特になく「安土城」と呼ばれます。地名の「安土」は、かつてこの地にあった目賀田氏の居城の山に、弓の練習用の「的（あづち＝射垜・盛り土）」があったことに由来すると言われています。"),
    Quiz(question: "人は今、世界で増え続けている。昔に安土城を築いた人は?", choices: ["豊臣秀吉","織田信康","鍋島直正","藤堂高虎"], answer: 1, explanation: "尾張国（現在の愛知県）出身。織田信秀の嫡男。家督争いの混乱を収めた後、桶狭間の戦いで今川義元を討ち取り、勢力を拡大した。足利義昭を奉じて上洛し、後には足利義昭を追放することで、畿内を中心に独自の中央政権（「織田政権」[注釈5]）を確立して天下人となった。しかし、天正10年6月2日（1582年6月21日）、家臣・明智光秀に謀反を起こされ、本能寺で自害した。"),
    Quiz(question: "今は丁度いい角度の階段。安土城の階段の角度は？", choices: ["46度","53度","角度不明","64度"], answer: 2, explanation: "安土城天守の内部階段は、焼失前の「天守指図（設計図）」によると北東隅に配置され、簓桁受け（ささらげたうけ）を用いた構造が礎石の配置と一致すると指摘されている。当時の天守は5重7階の構造で、内部は吹き抜け構造の可能性も示唆されており、上層階へ移動するための動線として設計されていた。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。安土城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 2, explanation: "安土城の石垣は、織田信長が築いた「高石垣（約10m以上）」の技術を駆使し、安土山や繖山（きぬがさやま）産の「湖東流紋岩」を自然のまま用いた「野面積」が特徴。天正の築城当時の姿が残る国指定特別史跡で、2024年の調査では、廃城時に意図的に破壊された痕跡も発見された。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、安土城であった事件とは？", choices: ["交通事故","津波","安土城放火","転落事故"], answer: 2, explanation: "安土城の最大の事件は、1582年の本能寺の変直後に起きた「安土城炎上」です。信長の死後、天正10年6月15日に天主（天守）が放火により焼失し、わずか築城6年で「幻の城」となりました。犯人は織田信雄（信長の次男）や明智秀満（光秀の重臣）など諸説あります。"),
    Quiz(question: "安土城の近くでオメガ３の入った魚が取れる。その魚は何か", choices: ["ヒラメ","カレイ","アユ","キス"], answer: 2, explanation: "鮎（アユ）は、主に1年で一生を終える「年魚」と呼ばれる淡水魚で、初夏から夏にかけて川の冷たい清流に生息する「清流の女王」です。藻を食べて育ち、スイカやキュウリのような香りがすることから「香魚」とも呼ばれ、特に塩焼きが定番です。")
]
        
let OdawaraQuizzes: [Quiz] = [
    Quiz(question: "日本百名城のうちの一つ、小田原城はどこにあるでしょうか。", choices: ["京都府","大阪府","神奈川県","東京都"], answer: 2, explanation: "小田原市は、箱根の玄関口に位置する「歴史・自然・利便性」が調和した神奈川県西部の中心都市です。小田原城を中心とした城下町であり、新幹線で東京まで約30分と通勤圏内ながら、海と山に囲まれた温暖で豊かな自然環境が魅力のトカイナカ（都会＋田舎）です。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から小田原城の別名は、", choices: ["霧ヶ城","小峰城","佐々木城","鶴ヶ城"], answer: 1, explanation: "小田原城の主な別名は「小峯城（小峰城）」または「小早川城」です。由来は城が築かれた「小峯（小峰）」という場所の名称や、江戸時代の領主であった小早川氏が由来とされる説があります。また、上杉謙信や武田信玄をも退けた歴史から「難攻不落の城」とも称されました。"),
    Quiz(question: "人は今、世界で増え続けている。昔に小田原城を築いた人は?", choices: ["豊臣秀吉","毛利元就","武田信玄","小田原北条氏"], answer: 3, explanation: "小田原北条氏（後北条氏）は、戦国時代（15世紀末〜16世紀末）に小田原城を本拠とし、約100年間にわたり関東地方を支配した戦国大名です。伊勢宗瑞（早雲）を初代とし、氏綱、氏康、氏政、氏直の5代にわたり、優れた領国経営（「禄寿応穏」）で安定した支配体制を築きましたが、1590年に豊臣秀吉の小田原征伐で滅亡しました。"),
    Quiz(question: "今は丁度いい角度の階段。小田原城の階段の角度は？", choices: ["52度","67度","55度","37度"], answer: 2, explanation: "小田原城天守閣内部の階段は、1960年の鉄筋コンクリート造による再建時にバリアフリーに配慮し、現代的な歩きやすい設計（通常の建築基準に準拠）になっているため、現存天守のような40〜50度以上の急勾配や手すりを持たない「壁」のような傾斜は存在しません。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。小田原城の石垣の積み方は？", choices: ["問知積","切込接","野面積","打込接"], answer: 0, explanation: "小田原城の石垣は、寛永9年（1632年）以降の改修で築かれた間知石積みが中心です。一方、関連史跡の「石垣山一夜城」は、1590年に豊臣秀吉が小田原征伐の際に築いた、関東初の本格的な「総石垣」の城跡です。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、小田原城であった事件とは？", choices: ["石垣が壊れた","松が倒れた","津波","合戦"], answer: 3, explanation: "小田原城に関連する歴史的な「事件」として最も有名なのは、1590年の豊臣秀吉による「小田原攻め（小田原征伐）」です。これは名胡桃城事件を機に北条氏が降伏・滅亡した戦いです。"),
    Quiz(question: "小田原城の近くでオメガ３の入った魚が取れる。その魚は何か", choices: ["クロマグロ","タラ","メバル","ホッケ"], answer: 0, explanation: "クロマグロは、サバ目サバ科に分類される海水魚の一種。 日本近海を含む太平洋の熱帯・温帯海域に広く分布する大型魚で、重要な食用魚である。生鮮魚介類として流通する場合にはホンマグロの名称も用いられる。 寿司ネタ、刺身等に使われ、日本の消費量が世界一であるが、資源の減少により厳しい漁獲制限が進められている。")
]

let YamagataQuizzes: [Quiz] = [
    Quiz(question: "日本百名城のうちの一つ、山形城はどこにあるでしょうか。", choices: ["山形県","長崎県","熊本県","青森県"], answer: 0, explanation: "山形市は、蔵王連峰に囲まれた自然豊かな山形県の県都（人口約25万人）です。戦国武将・最上義光が整備した城下町の風情と、歴史的な洋館（文翔館）が残り、秋の「芋煮会」や「山寺（立石寺）」、スキー・温泉（蔵王）が有名。さくらんぼや米、山形牛などの食、豊かな自然環境と便利な都市機能が調和した住みやすい街です。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から山形城の別名は、", choices: ["喜春城","菖蒲城","霧ヶ城","蕗城"], answer: 2, explanation: "山形城の別名は「霞ヶ城（かすみがじょう）」です。この由来は、慶長5年（1600年）の長谷堂合戦の際、敵陣（富神山）から城を眺めたところ、霞（かすみ）がかかっているように見え、城の姿が隠れて見えなかったというエピソードに基づいています。"),
    Quiz(question: "人は今、世界で増え続けている。昔に山形城を築いた人は?", choices: ["豊臣秀吉","京極高和","浅野長直","最上義光"], answer: 3, explanation: "最上 義光は、戦国時代から江戸時代前期にかけての出羽国の大名。最上氏第11代当主。出羽山形藩の初代藩主。 南羽州に勢力を広げ、縁戚である伊達輝宗・政宗と争う。関ヶ原の戦いにおいて東軍につき、慶長出羽合戦にて上杉家の直江兼続を退け、57万石の版図を築いた。"),
    Quiz(question: "今は丁度いい角度の階段。山形城の階段の角度は？", choices: ["43度","62度","階段なし","34度"], answer: 2, explanation: "山形城（霞城公園）の天守は江戸時代初期に設計図が存在したものの、最終的に建築されなかったため、現存する天守内部の階段はありません。現在は本丸大手門の高麗門や一文字門櫓などが木造復元されており、これらの櫓内部に見学可能な階段が存在する場合があります。"),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。山形城の石垣の積み方は？", choices: ["打込接と切込接","切込接と打込接","野面積とまずめ石","打込接と野面積"], answer: 2, explanation: "山形城は、本丸（2.83ヘクタール）・二ノ丸（27.99ヘクタール）・三ノ丸（234.86ヘクタール）を三重の堀と土塁で囲まれた輪郭式の平城で、東北では最大です。外郭である三ノ丸は、現存する日本最大の天守がある姫路城の外郭（約233ヘクタール）や内曲輪うちくるわ（約23ヘクタール）よりもそれぞれ広くなっております。「北の関ヶ原合戦」と呼ばれた慶長出羽合戦けいちょうでわかっせんにおいては、城郭が霞で隠れて見えなかったことから、「霞ヶ城かすみがじょう」と呼ばれたと地元では語り継がれています。石垣には馬見ヶ崎川まみがさきがわで採掘された玉石（安山岩）を割った石材を用い、割り面を前面に利用しています。本丸は御殿のみで天守はありませんでしたが、二ノ丸には江戸時代前期まで三階櫓さんかいやぐらがありました。今も残る二ノ丸の堀や土塁・石垣は、最上氏改易後の元和げんな8年（1622）に城主となった鳥居忠政とりい ただまさやその後の保科正之ほしな まさゆきにより改修されたと伝えられています。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、山形城であった事件とは？", choices: ["石垣が壊れた","津波","火事","暗殺"], answer: 3, explanation: "山形城主・最上義光は、豊臣秀次事件（1595年）に連座して娘の駒姫が処刑されるという惨劇に遭いました。その後、最上家では家督や領地を巡る争いが起き、義光の嫡男・義康が、1590年代後半に暗殺されるという事件が発生したとされています（暗殺場所は鶴岡周辺の街道とも、山形へ向かう途中とも言われる）。この悲劇的な家督争いや豊臣との決別が、最上義光が徳川家康へ傾倒し、後の「北の関ヶ原」と呼ばれる関ヶ原の戦いへと繋がった背景にあります。"),
    Quiz(question: "山形城の近くでオメガ３の少ないけれど入った魚が取れる。その魚は何か", choices: ["シラス","トビウオ","カツオ","サケ"], answer: 3, explanation: "サケは、サケ目サケ科サケ属の魚。狭義には種としてのO.keta の標準和名であるが、広義にはサケ類一般を指すことが多い。")
]

let BitchuMatsuyamaQuizzes: [Quiz] = [
    Quiz(question: "現存12天守。日本の城で12個しかないうちの一つ、備中松山城はどこにあるでしょうか。", choices: ["徳島県","岡山県","鹿児島県","鳥取県"], answer: 1, explanation: "岡山県の備中松山（高梁市）は、標高430mの臥牛山頂上に現存する日本唯一の山城「備中松山城」で有名です。秋から冬の早朝には雲海に浮かぶ「天空の城」が見られ、江戸時代の天守や石垣が残る貴重な史跡です。周辺には武家屋敷やレトロな町並み、猫城主「さんじゅーろー」も人気です。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から備中松山城の別名は、", choices: ["高梁城","錦城","蕗城","金亀城"], answer: 0, explanation: "別名は「高梁城（たかはしじょう）」です。江戸時代の松山藩の所在地が「松山」から「高梁」へ改称された際、伊予松山城（愛媛県）と区別するために地名である「高梁」が採用されたことに由来します。標高480mの臥牛山（がぎゅうざん）山頂に位置する現存天守12城の一つです"),
    Quiz(question: "人は今、世界で増え続けている。昔に備中松山城を築いた人は?", choices: ["秋庭三郎重信","森忠正","堀尾吉晴","伊達政宗"], answer: 0, explanation: "秋庭重信は、承久の乱後、鎌倉幕府から戦功の賞として備中国有漢郷の地頭職に補せられた。いわゆる新補地頭の一人であった。その後、任地に赴き、現在の上房郡有漢町貞守、台ヵ鼻に台ヵ鼻城を築き、以後、約18年間ここを居城とした。元治元年（1240）、備中路における最大の軍事拠点となる臥牛山の大松山に、初めて城を築いたのも秋庭三郎重信であった。鎌倉幕府は新見東寺の荘園紛争につき、領家新見九郎貞直の横領を止めさせるように、秋庭備中守（重明）を備中における実力第一人者として命じたが、効果もなく、貞直の横領は重明が備中松山城主となるまで続いた。また、重明は有漢町の土井に屋敷を構え、その正面に防備を施した常山城を築き、地域荘民からの信頼も得て、徐々に国衆としての地位・軍力を確立していった。正平年間の頃には、京都の足利義詮の御教書を受け、新見荘領家職の乱暴まで止めさせている。"),
    Quiz(question: "今は丁度いい角度の階段。昔の備中松山城の階段の角度は？", choices: ["34度","54度","73度","46度"], answer: 1, explanation: "備中松山城の天守内部にある階段は、現存天守特有の約50度以上の急勾配です。一階から二階へつながる階段は特に急で、狭く上りにくい構造となっており、防御上の理由から敵が侵入しにくいように工夫されています。木造で幅が狭く、踏み面も小さいため、手すりを使って慎重に上り下りする必要がある。 "),
    Quiz(question: "今、積むのはつみき昔、お城に積んでいた石垣。備中松山城の石垣の積み方は？", choices: ["まづめ石","切込接","野面積","打込接"], answer: 2, explanation: "備中松山城（岡山県高梁市）の石垣は、標高430mの臥牛山頂に自然の岩盤と人工の石垣が融合した「難攻不落」の山城の象徴です。特に戦国時代から残る野面積（のづらづみ）や、近世の精巧な算木積みが混在し、大手門付近や二重櫓周辺の断崖絶壁にそびえる石垣が最大の見どころ。"),
    Quiz(question: "トランプ大統領が大統領になってから色々な事件が起きている気がする。昔、備中松山城であった事件とは？", choices: ["脱走事件","備中松山城の宝が無くなった","お城が半分崩れた","泥棒"], answer: 0, explanation: "備中松山城における「事件」は、主に2018年頃に起きた猫城主「さんじゅーろー」の脱走・行方不明騒動（大捜索事件）を指すことが多いです。現在は無事に帰還し、観光PRの「一日警察署長」を務めるなど、城のシンボルとして活躍しています。"),
    Quiz(question: "備中松山城の近くで取れるオメガ３の入った魚は何か", choices: ["アユ","キス","カレイ","タラ"], answer: 0, explanation: "アユは、キュウリウオ目に分類される、川や海などを回遊する魚である。「清流の女王」とも呼ばれている。なお、漢字の「鮎」は、中国ではナマズを指し、アユという意味は日本での国訓である。")
]

let HirosakiQuizzes: [Quiz] = [
    Quiz(question: "現存12天守。日本の城で12個しかないうちの一つ、弘前城はどこにあるでしょうか。", choices: ["徳島県","青森県","鹿児島県","鳥取県"], answer: 1, explanation: "弘前城は旧国名の陸奥國、現在の青森県にある。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から弘前城の別名は、", choices: ["なし","月山城","蕗城","金亀城"], answer: 0, explanation: "築城地が昔、鷹岡と呼ばれていたことからこの別名がついた。築城当初は『鷹岡城』という名前だったが、天守が火災で消失したため『弘前城』へ改名した。"),
    Quiz(question: "人は今、世界で増え続けている。昔に弘前城を築いた人は?", choices: ["秋庭重信","森忠正","堀尾吉晴","伊達政宗"], answer: 0, explanation: "1590(天正18)年、津軽為信が津軽地方の統一を成し遂げ、豊臣秀吉から津軽3郡の領有を認めらた。その後、藩政の拠点となる城の築城を決意し、1610(慶長15)年、2代目藩主の信牧の時に築城を開始。4代目藩主信政の時代に完成したと言われている。"),
    Quiz(question: "弘前城の魅力はなんでしょう？", choices: ["漆黒の天守","切込接の石垣","神経痛に効くモール温泉","城址を埋め尽くす2600本の桜"], answer: 2, explanation: "弘前城には「桜守（さくらもり）」と言われる専門スタッフが枝の剪定や管理を行っているため、100年を超える桜もボリュームある花を咲かせることができると言われている。"),
    Quiz(question: "天守の屋根は「銅板葺」という、薄く伸ばした銅板を重ねる方法をとっている。その理由に当てはまらないものはどれか？", choices: ["雪に強い","地震に強い","見栄えが良い","海風に強い"], answer: 3, explanation: "薄く延ばした銅板を用いて屋根を葺く伝統的な工法。軽量で耐久性が高く、防火性にも優れるこの工法は古くから重要な建築物に採用されてきた。仕上がり直後はブロンズ色に光沢を帯びているが、酸化して濃緑、青緑と色を変えていくのも魅力である。"),
    Quiz(question: "日本は山が多く、国土の4分の3が山地だ。弘前城からは津軽富士と呼ばれる山が見える。その山の名前は？", choices: ["栗駒山","岩木山","八甲田山","月山"], answer: 1, explanation: "日本は山が多く、国土の4分の3が山地なので山が見渡せるお城は多い。弘前城は本丸西エリアから岩木山が一望できる。"),
    Quiz(question: "江戸時代には、火事がよく起こっていました。弘前城も1627年に被害を受けているが、その時の火事の原因はなんだったのか？", choices: ["落雷","焚き火","放火","火入れ"], answer: 0, explanation: "城築城当初、5層の天守があったが、1627年（寛永4年）、火事により焼失した。1810年（文化7年）まで天守の新造が認められなかったため、天守があった場所には櫓が建てられた。")
]

let KochiQuizzes: [Quiz] = [
    Quiz(question: "名城100このうちの一つ、高知城がある高知県の旧国名は？", choices: ["伊予","土佐","紀井","河内"], answer: 1, explanation: "高知城は旧国名の土佐国、現在の高知県にある。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中から高知城の別名は、", choices: ["なし","月山城","蕗城","金亀城"], answer: 0, explanation: "土佐漆喰の白壁と瓦葺の灰色が鷹の羽に似ていることからこの別名がつけられた。"),
    Quiz(question: "人は今、世界で増え続けている。昔に弘前城を築いた人は?", choices: ["秋庭重信","森忠正","堀尾吉晴","伊達政宗"], answer: 0, explanation: "豊臣秀吉に仕え、数々の功績を上げたが、関ヶ原の戦い（1600年)では東軍の徳川家康に味方し、土佐一国を与えられた。"),
    Quiz(question: "もともとこの土地に住んでいたのは何氏でしょう", choices: ["毛利氏","小早川氏","長宗我部氏","細川氏"], answer: 3, explanation: "1585年四国を統一するも、その後、豊臣秀吉の四国征伐に降伏し土佐のみの領有を認められた。関ヶ原の戦いでは西軍の豊臣側に味方し、領地を没収された。"),
    Quiz(question: "今、家を作るのにかかる時間は1年くらい。高知城の全城郭が完成するのに何年間かかったか？", choices: ["三年間","五年間","八年間","十年間"], answer: 3, explanation: "1601年に開始し、1611年に完成した。1727年に城下町の大火事によって大手門以外のほとんどの建物が消失したが、1753年までに創建当時の姿のまま再建された。"),
    Quiz(question: "高知城の「こうち」は何度も漢字が変わっている。この中で、一度も使われたことない漢字はどれ？", choices: ["高智","高知","河中","光地"], answer: 3, explanation: "城山は江ノ口川と鏡川に挟まれていたため、「河中山」と呼ばれていたが、水害が多かったことから「高智」となり、その後現在の「高知」に変わった。"),
    Quiz(question: "高知城の藩主の中で、賢君と呼ばれ、評判が高いのは誰でしょう", choices: ["3代山内忠豊","7代山内豊常","11代山内豊興","15代山内豊信"], answer: 3, explanation: "吉田東洋を仕置役に抜擢し、財政・海防・教育改革を進めた。幕政にも関わり、15代将軍徳川慶喜に大政奉還を関白した。")
]

let HikoneQuizzes: [Quiz] = [
    Quiz(question: "彦根域を訪れた際、出迎えてくれる人気キャラクターは", choices: ["くまモン","ひこにゃん","ふなっしー","せいとくん"], answer: 1, explanation: "3代目藩主、伊井直孝を雷雨から救ったと言われている猫をモチーフとしている。"),
    Quiz(question: "天守閣から一望できるものは", choices: ["大阪湾","日本海","瀬戸内海","琵琶湖"], answer: 3, explanation: "彦根城の天守や西の丸からは、琵琶湖を一望することができる。"),
    Quiz(question: "彦根藩主の庭園として国の名勝に指定されているものは", choices: ["兼六園","玄宮園","後楽園","偕楽園"], answer: 1, explanation: "4代藩主井伊直興により造園された。中央に大きな池泉には4つの中島にはさまざまな形式の橋が架けれ、回遊式庭園となっている。"),
    Quiz(question: "徳川四天王のうち最も大きな知行国を与えられた、徳川家康の腹心とも言える武将は", choices: ["本田忠勝","榊原康政","井伊直政","酒井忠次"], answer: 2, explanation: "15歳の時に徳川家康の家臣となり、豊臣秀吉が死去した後の覇権争いでは、家康の右腕として他勢力と交渉して味方に引き入れることに成功した。"),
    Quiz(question: "井伊軍団は落主以下家臣にいたるまで甲冑のみならず、旗、馬印、吹き流し、采配など全てある色で統一されており敵陣に真っ先に突き進み果敢に攻め立てたため井伊の◯鬼と恐れられていましたが何鬼と恐れられていたのでしょうか。", choices: ["黒鬼","青鬼","緑鬼","赤鬼"], answer: 3, explanation: "井伊軍団は家臣にいたるまで甲冑のみならず、旗、馬印、吹き流し、采配など全て赤で統一されており敵陣に真っ先に突き進み果敢に攻め立てたため、赤鬼と恐れられていた。"),
    Quiz(question: "彦根城の建物は徳川家康の支援で、井伊家が琵琶湖周辺の廃城の建物や用材を活用して達てました。では国宝の天守はもともとどの域のものだったでしょうか。", choices: ["大津城","佐和山城","長浜城","小谷城"], answer: 0, explanation: "天守は大津城から移築されたといわれ、政治的象徴としての外観の美しさだけでなく、城本来の機能である軍事面でも優れていて、昭和27年（1952）に国宝に指定された。"),
    Quiz(question: "廊下橋前の天秤櫓は大手門と表門からの道が合流する要に位置し、本丸を防御するための重要な櫓ですが、右手の高石垣が築城当初に越前の岩工大工たちによって築かれた石垣でありいまだに現存しているものですが何という積み方によって積まれたものでしょうか。", choices: ["ごぼう積み","大根積み","人参積み","干し芋積み"], answer: 0, explanation: "野面積の一種。胴長な石を用いて、短い面を前面に出し、長い面を奥にする積み方。粗野に見えるが堅固な石垣となる。")
]

let NagoyaQuizzes: [Quiz] = [
    Quiz(question: "名城100このうちの一つ、名古屋城はどこにあるでしょうか。", choices: ["徳島県","愛知県","岐阜県","高知県"], answer: 1, explanation: "名古屋城は旧国名の尾張国、現在の愛知県にある。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中か名古屋城の別名は、", choices: ["綿水城","なし","金鯱城","稲葉山城"], answer: 3, explanation: "天守の屋根に金の鯱（鯱鉾）が鎮座していることからこの別名がつけられた。"),
    Quiz(question: "名古屋城は徳川家康が全国の大名に築城させた城である。これをなんというか？", choices: ["天下泰平","天下布武","天下普請","天下統一"], answer: 2, explanation: "天下普請は大名の財力の消耗や徳川家への忠節を確認するために行われた。名古屋城は加藤清正、福島正則など豊臣家に従ってきた大名20家が築城を命じられた。"),
    Quiz(question: "名古屋城が作られ始めたのは1610年のことだ。名古屋城が完成したのは何年？", choices: ["1613年","1615年","1620年","1623年"], answer: 1, explanation: "天守台の石垣は、名手とされた加藤清正が自ら申し出て、3ヶ月とかからずに築き上げた。1612年(慶長17)には、大小天守が完成。大天守大棟には金鯱が上げられ、尾張徳川家の象徴となる天守になった。同年に本丸御殿建設にも着工し、1615年(慶長20)に完成した。"),
    Quiz(question: "名古屋城のシンボルでもある有名な鯱鉾。雌の大きさは8尺3寸。雄の鯱鉾の大きさは？", choices: ["8尺","8尺3寸","8尺5寸","9尺3寸"], answer: 2, explanation: "北側を雄、南側を雌です。雄は高さ2.621m、重量1,272㎏。雌は高さ2.579m、重量1,215㎏。からだを覆う金のウロコには18金が使用されている。"),
    Quiz(question: "明治5年にある国の公使が名古屋城を訪れた。その人の名はフォン・プラントン。どこの国の人？", choices: ["イギリス","ドイツ","フランス","ギリシャ"], answer: 1, explanation: "明治5年に名古屋城を訪れたプラントン公使はその美しさに感動し、明治政府に名古屋城を保蔵するように提言した。"),
    Quiz(question: "名古屋城の本丸御殿は戦争で焼失したが、2018年に復元された。この本丸御殿は一部屋を除いて全てある種類の木材が使われている。その木材は何か？", choices: ["桧","松","槙","杉"], answer: 0, explanation: "本丸御殿のほかの部屋は、総ヒノキ造りだが、黒木書院だけは良質な松材が用いられている。この部屋は清洲内の家康の部屋を移築したとも言われている。")
]

let GoryokakuQuizzes: [Quiz] = [
    Quiz(question: "名城100このうちの一つ、五稜郭はどこにあるでしょうか。", choices: ["北海道","青森県","山形県","岩手県"], answer: 0, explanation: "江戸時代、蝦夷地と呼ばれていた北の地に建てられた。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中か五稜郭の別名は？", choices: ["霧ヶ城","なし","柳野城","鶴ヶ城"], answer: 2, explanation: "当時は水はけの悪い土地で、至る所に柳が生えていたことからこの別名がついた。"),
    Quiz(question: "五稜郭はどのような形をしているか？", choices: ["六角形","星形","三角形","楕円形"], answer: 1, explanation: "星型には2つの目的があったと考えられている。一つ目はどの方向から攻められても必ず2方向から銃砲で反撃できる「十字砲火」を可能すること。もう一つは諸外国への技術力や軍事力をアピールであった。"),
    Quiz(question: "江戸時代の末期に築城された星型の五稜郭は防御に優れているが、どの国との戦いを想定していたか？", choices: ["清","イギリス","ロシア帝国","アメリカ合衆国"], answer: 3, explanation: "18世紀末から19世紀の初め、ロシアの南下政策に感じた幕府は、松前藩に代わって蝦夷地を自ら直轄し、その後、五稜郭を築城することにした"),
    Quiz(question: "このような星型の城は日本に2つある。もう一つは何城か？", choices: ["龍岡城","松前城","多賀城","白河小峰城"], answer: 2, explanation: "星型の城（西洋式稜堡式城郭）は、北海道函館市の「五稜郭」と、長野県佐久市の「龍岡城」の2カ所のみ現存"),
    Quiz(question: "五稜郭を設計したのは蘭学者の武田斐三郎だが、どこの国から学んだか？", choices: ["イギリス","ドイツ","フランス","アメリカ合衆国"], answer: 2, explanation: "1855年（安政2年）に函館に来たフランス軍艦コンスタンティーン号の軍人からパリの都市要塞について学んだ"),
    Quiz(question: "明治新政府と旧幕府軍の最後の戦いが行われた箱館戦争で戦死した、新撰組副長の名は？", choices: ["近藤勇","沖田総司","永倉新八","土方歳三"], answer: 3, explanation: "明治元年(1868)8月，品川沖を脱走した旧幕府脱走軍艦隊が蝦夷地へ到着し、戊辰戦争の最後の戦いとなる箱館戦争が開始された。脱走軍の最大の砦であった弁天岬台場がほとんど壊滅状態となり，その救援に向かった新撰組副長の土方歳三は異国橋（いこくばし。現在の十字街電停付近）あたりで銃弾に撃たれて戦死した。")
]

let OshiQuizzes: [Quiz] = [
    Quiz(question: "名城100このうちの一つ、忍城はどこにあるでしょうか。", choices: ["神奈川県","愛知県","埼玉県","静岡県"], answer: 0, explanation: "忍城は現在の東京都、埼玉県、神奈川県に位置する武蔵國にあった。"),
    Quiz(question: "日本100名城の中で90以上の別名がある。その中か忍城の別名は？", choices: ["霧ヶ城","なし","浮城","鶴ヶ城"], answer: 2, explanation: "忍城は沼地や湿地に囲まれた場所に築かれたため、豊臣軍による水攻めの際も本丸が水に浮かぶように見えたことから「浮き城」呼ばれた。"),
    Quiz(question: "忍城を築いたのは何氏？", choices: ["成田氏","上杉氏","北条氏","太田氏"], answer: 1, explanation: "15世紀後半、北条氏に属していた成田氏によって築城された。"),
    Quiz(question: "豊臣秀吉の小田原攻めを中心とした関東統一の中で、忍城にも豊臣軍が攻め入った。誰が率いた軍が忍城に向かったか？", choices: ["池田三成","伊達政宗","徳川家康","真田幸村"], answer: 0, explanation: "石田三成は20,000人以上の軍勢を引き連れて忍城を包囲、全長28kmにも及ぶ堤を築き、水攻めをしたが、落城しなかった。"),
    Quiz(question: "忍城は〇〇名城として知られています。〇〇とはなんか？", choices: ["関東七名城","関東三大山城","日本三水城","日本三大天空城"], answer: 0, explanation: "川越城、忍城、前橋城、金山城、唐沢山城、宇都宮城、佐竹城を合わせて関東七名城と言う。"),
